Here's a step-by-step guide along with sample code for a Discord bot using Discord.js v14:

### 1. Set up a new project
First, create a new directory for your project and initialize a new Node.js project inside it:

```bash
mkdir discord-ban-bot
cd discord-ban-bot
npm init -y
```

### 2. Install Discord.js
Install the latest version of Discord.js:

```bash
npm install discord.js
```

### 3. Create a bot on the Discord Developer Portal
Go to the [Discord Developer Portal](https://discord.com/developers/applications) and create a new application. Then, navigate to the "Bot" tab and add a bot to your application. Copy the bot token, as you'll need it to run the bot.

### 4. Register the `ban` slash command
Register the `ban` command in your Discord application. Go to the "OAuth2" tab, enable "OAuth2 URL Generator," and set the scopes to include `bot`, `applications.commands`, and `ban`. This will generate a URL to register the command.

### 5. Write the code
Create a file named `index.js` and add the following code:

```javascript
const { Client, GatewayIntentBits, PermissionsBitField, REST } = require('discord.js');
const { token, clientId, guildId } = require('./config.json'); // Create a config.json with your bot token, client ID, and guild ID

const commands = [
    {
        name: 'ban',
        description: 'Ban a user',
        options: [
            {
                name: 'user',
                type: 6, // USER type
                description: 'The user to ban',
                required: true,
            },
        ],
    },
];

const rest = new REST({ version: '10' }).setToken(token);

(async () => {
    try {
        console.log('Started refreshing application (/) commands.');

        await rest.put(
            Routes.applicationGuildCommands(clientId, guildId),
            { body: commands },
        );

        console.log('Successfully reloaded application (/) commands.');
    } catch (error) {
        console.error(error);
    }
})();

const client = new Client({
    intents: [
        GatewayIntentBits.Guilds,
        GatewayIntentBits.GuildMessages,
        GatewayIntentBits.GuildMessageReactions,
        GatewayIntentBits.GuildMembers,
    ],
});

client.once('ready', () => {
    console.log('Ready!');
});

client.on('interactionCreate', async interaction => {
    if (!interaction.isCommand()) return;

    const { commandName } = interaction;

    if (commandName === 'ban') {
        const user = interaction.options.getUser('user');
        const member = interaction.guild.members.cache.get(user.id);

        if (member) {
            if (interaction.member.permissions.has(PermissionsBitField.Flags.BanMembers)) {
                try {
                    await member.ban();
                    await interaction.reply(`${user.tag} has been banned.`);
                } catch (error) {
                    console.error(error);
                    await interaction.reply('I was unable to ban the member');
                }
            } else {
                await interaction.reply('You do not have permission to ban members.');
            }
        } else {
            await interaction.reply('The user is not in the guild.');
        }
    }
});

client.login(token);
